        {% block stylesheets %}{% endblock %}

        {% block javascripts %}
            {% block importmap %}{{ importmap(\x27app\x27) }}{% endblock %}
        {% endblock %}
    </head>

    <body class=\"d-flex flex-column min-vh-100 {% block body_class %}{% endblock %}\">
        {% include \x27partials/_header.html.twig\x27 %}

        <main class=\"flex-grow-1\" style=\"padding-top: 80px;\">
